-- Elimina prima i biglietti degli ordini non completati
DELETE t FROM tickets t
INNER JOIN orders o ON t.orderId = o.id
WHERE o.status != 'completed';

-- Poi elimina gli ordini non completati
DELETE FROM orders WHERE status != 'completed';

-- Verifica risultato
SELECT id, orderNumber, status, totalAmount, createdAt FROM orders ORDER BY createdAt DESC;

